// Generated by Copilot
import type { TlantiCase, TlantiCaseAsset, TlantiCaseAssetRole, TlantiCasePipeline } from '@/stores/tlantidb-case-store';

export type ClinicalWorkflowStage = 'intake' | 'scan' | 'design' | 'manufacture';

export interface ClinicalChecklistItem {
  id: string;
  label: string;
  description: string;
  stage: ClinicalWorkflowStage;
  required: boolean;
  completed: boolean;
  roles: TlantiCaseAssetRole[];
}

export interface ClinicalStageSuggestion {
  id: string;
  stage: ClinicalWorkflowStage;
  label: string;
  description: string;
  roles: TlantiCaseAssetRole[];
  completed: boolean;
  required: boolean;
}

export interface NextClinicalAction {
  stage: ClinicalWorkflowStage;
  label: string;
  description: string;
  roles: TlantiCaseAssetRole[];
}

export interface SmartAssetRoutingContext {
  activeCase: TlantiCase;
  existingAssets: TlantiCaseAsset[];
  fileName: string;
  category: TlantiCaseAsset['category'];
  detectedRole: TlantiCaseAssetRole;
}

const SCAN_ROLES: TlantiCaseAssetRole[] = ['dicom-study', 'prep-scan', 'antagonist-scan', 'bite-registration', 'gingiva-scan'];
const DESIGN_ROLES: TlantiCaseAssetRole[] = ['restoration-model', 'shade-reference', 'smile-photo', 'pre-op-photo', 'clinical-photo'];
const MANUFACTURE_ROLES: TlantiCaseAssetRole[] = ['manufacturing-report', 'lab-prescription'];

function hasRole(assets: TlantiCaseAsset[], roles: TlantiCaseAssetRole[]) {
  return assets.some((asset) => roles.includes(asset.role));
}

function getRoleCount(assets: TlantiCaseAsset[], role: TlantiCaseAssetRole) {
  return assets.filter((asset) => asset.role === role).length;
}

function caseNeedsImplantPlanning(activeCase: TlantiCase) {
  return Object.values(activeCase.toothMap).some((item) => item.implantMode && item.implantMode !== 'none');
}

function caseNeedsOpposingRecords(activeCase: TlantiCase) {
  return activeCase.occlusionScanType !== 'single_model' || Object.values(activeCase.toothMap).some((item) => item.antagonist);
}

function caseNeedsShadeReference(activeCase: TlantiCase) {
  return Object.values(activeCase.toothMap).some((item) => item.selected && !item.antagonist);
}

export function deriveChecklistFromCase(activeCase: TlantiCase, assets: TlantiCaseAsset[]): ClinicalChecklistItem[] {
  const needsImplant = caseNeedsImplantPlanning(activeCase);
  const needsOpposing = caseNeedsOpposingRecords(activeCase);
  const needsShade = caseNeedsShadeReference(activeCase);

  return [
    {
      id: 'prescription',
      label: 'Lab prescription',
      description: 'Attach the clinical/lab order that anchors the restorative request.',
      stage: 'intake',
      required: true,
      completed: hasRole(assets, ['lab-prescription']),
      roles: ['lab-prescription'],
    },
    {
      id: 'primary-scan',
      label: 'Primary scan',
      description: 'Need prep scan, DICOM or restorative model before design can move forward.',
      stage: 'scan',
      required: true,
      completed: hasRole(assets, ['prep-scan', 'dicom-study', 'restoration-model']),
      roles: ['prep-scan', 'dicom-study', 'restoration-model'],
    },
    {
      id: 'opposing-record',
      label: 'Opposing / bite record',
      description: 'Occlusion context is required for multi-model and antagonist cases.',
      stage: 'scan',
      required: needsOpposing,
      completed: !needsOpposing || hasRole(assets, ['antagonist-scan', 'bite-registration']),
      roles: ['antagonist-scan', 'bite-registration'],
    },
    {
      id: 'shade-reference',
      label: 'Shade reference',
      description: 'Clinical photos or shade tabs to validate esthetics and ceramic recipe.',
      stage: 'design',
      required: needsShade,
      completed: !needsShade || hasRole(assets, ['shade-reference', 'smile-photo', 'clinical-photo']),
      roles: ['shade-reference', 'smile-photo', 'clinical-photo'],
    },
    {
      id: 'implant-planning',
      label: 'Implant planning data',
      description: 'Implant cases should have CBCT/DICOM and gingiva or guide records attached.',
      stage: 'scan',
      required: needsImplant,
      completed: !needsImplant || hasRole(assets, ['dicom-study', 'gingiva-scan']),
      roles: ['dicom-study', 'gingiva-scan'],
    },
    {
      id: 'handoff',
      label: 'Manufacturing handoff',
      description: 'Reports and prescriptions should be ready before manufacturing/export.',
      stage: 'manufacture',
      required: false,
      completed: hasRole(assets, ['manufacturing-report']),
      roles: ['manufacturing-report'],
    },
  ];
}

export function deriveSuggestedAssetsByStage(activeCase: TlantiCase, assets: TlantiCaseAsset[]): ClinicalStageSuggestion[] {
  const checklist = deriveChecklistFromCase(activeCase, assets);
  return checklist.map((item) => ({
    id: item.id,
    stage: item.stage,
    label: item.label,
    description: item.description,
    roles: item.roles,
    completed: item.completed,
    required: item.required,
  }));
}

export function deriveNextClinicalAction(activeCase: TlantiCase, assets: TlantiCaseAsset[]): NextClinicalAction | null {
  const checklist = deriveChecklistFromCase(activeCase, assets);
  const nextRequired = checklist.find((item) => item.required && !item.completed);
  if (nextRequired) {
    return {
      stage: nextRequired.stage,
      label: nextRequired.label,
      description: nextRequired.description,
      roles: nextRequired.roles,
    };
  }

  const nextOptional = checklist.find((item) => !item.completed);
  if (nextOptional) {
    return {
      stage: nextOptional.stage,
      label: nextOptional.label,
      description: nextOptional.description,
      roles: nextOptional.roles,
    };
  }

  return null;
}

export function derivePipelineFromClinicalAssets(activeCase: TlantiCase, assets: TlantiCaseAsset[]): TlantiCasePipeline {
  const checklist = deriveChecklistFromCase(activeCase, assets);
  const requiredItems = checklist.filter((item) => item.required);
  const allRequiredComplete = requiredItems.every((item) => item.completed);

  return {
    scan: hasRole(assets, SCAN_ROLES) || Boolean(activeCase.pipeline?.scan),
    design: hasRole(assets, DESIGN_ROLES) || (Boolean(activeCase.pipeline?.design) || allRequiredComplete),
    model: hasRole(assets, ['restoration-model']) || Boolean(activeCase.pipeline?.model),
    manufacture: hasRole(assets, MANUFACTURE_ROLES) || Boolean(activeCase.pipeline?.manufacture),
    export: Boolean(activeCase.pipeline?.export || activeCase.lastInteropXmlPath),
  };
}

export function routeAssetRoleByClinicalContext({ activeCase, existingAssets, fileName, category, detectedRole }: SmartAssetRoutingContext): TlantiCaseAssetRole {
  const normalized = fileName.toLowerCase();
  if (detectedRole !== 'clinical-photo' && detectedRole !== 'clinical-note' && detectedRole !== 'restoration-model') {
    return detectedRole;
  }

  if (category === 'model') {
    if (caseNeedsOpposingRecords(activeCase) && getRoleCount(existingAssets, 'prep-scan') > 0 && getRoleCount(existingAssets, 'antagonist-scan') === 0) {
      return 'antagonist-scan';
    }

    if (activeCase.occlusionScanType === 'bite_registration' && /bite|occlusion/i.test(normalized)) {
      return 'bite-registration';
    }

    if (getRoleCount(existingAssets, 'prep-scan') === 0) {
      return 'prep-scan';
    }

    return 'restoration-model';
  }

  if (category === 'image') {
    if (caseNeedsShadeReference(activeCase) && getRoleCount(existingAssets, 'shade-reference') === 0) {
      return 'shade-reference';
    }

    if (getRoleCount(existingAssets, 'pre-op-photo') === 0) {
      return 'pre-op-photo';
    }

    if (/smile|frontal/i.test(normalized)) {
      return 'smile-photo';
    }

    return 'clinical-photo';
  }

  if (category === 'document') {
    if (getRoleCount(existingAssets, 'lab-prescription') === 0) {
      return 'lab-prescription';
    }

    return 'clinical-note';
  }

  if (category === 'report') {
    return 'manufacturing-report';
  }

  if (category === 'dicom') {
    return 'dicom-study';
  }

  return detectedRole;
}

export function groupAssetsByRole(assets: TlantiCaseAsset[]) {
  const grouped = new Map<TlantiCaseAssetRole, TlantiCaseAsset[]>();
  assets.forEach((asset) => {
    const current = grouped.get(asset.role) ?? [];
    current.push(asset);
    grouped.set(asset.role, current);
  });

  return Array.from(grouped.entries()).sort((left, right) => left[0].localeCompare(right[0]));
}
